function Btn({children,primary,small,full,href,onClick,disabled}){
  const [hov,setHov]=useState(false);
  const base={display:"inline-flex",alignItems:"center",justifyContent:"center",gap:7,padding:small?"7px 16px":"12px 26px",fontSize:small?9:10,letterSpacing:small?2:2.5,textTransform:"uppercase",fontFamily:"sans-serif",fontWeight:600,cursor:disabled?"not-allowed":"pointer",opacity:disabled?.55:1,border:"none",textDecoration:"none",transition:"all .25s",position:"relative",...(full?{width:"100%"}:{})};
  const variant=primary?{background:C.red,color:"#fff"}:{background:"transparent",color:C.white,border:`1px solid ${C.border2}`};
  const hs=hov?(primary?{transform:"translateY(-2px)",boxShadow:`0 8px 32px ${C.redGlow},0 0 0 1px ${C.red}`}:{borderColor:C.red,color:C.red,transform:"translateY(-2px)"}):{};
  const props={style:{...base,...variant,...hs},onMouseEnter:()=>setHov(true),onMouseLeave:()=>setHov(false),onClick,disabled};
  return href?<a href={href} target="_blank" rel="noreferrer" {...props}>{children}</a>:<button {...props}>{children}</button>;
}
function Reveal({children,delay=0}){
  const ref=useRef();const[vis,setVis]=useState(false);
  useEffect(()=>{const o=new IntersectionObserver(([e])=>{if(e.isIntersecting){setVis(true);o.disconnect();}},{threshold:.12});if(ref.current)o.observe(ref.current);return()=>o.disconnect();},[]);
  return <div ref={ref} style={{opacity:vis?1:0,transform:vis?"translateY(0)":"translateY(36px)",transition:`opacity .65s ${delay}s, transform .65s ${delay}s`}}>{children}</div>;
}
function Particles(){
  const canvas=useRef();const raf=useRef();
  useEffect(()=>{
    const c=canvas.current;if(!c)return;
    const ctx=c.getContext("2d");
    const resize=()=>{c.width=c.offsetWidth;c.height=c.offsetHeight;};
    resize();window.addEventListener("resize",resize);
    const pts=Array.from({length:55},()=>({x:Math.random()*c.width,y:Math.random()*c.height,vx:(Math.random()-.5)*.28,vy:(Math.random()-.5)*.28,r:Math.random()*1.4+.4,col:Math.random()>.82?C.red:"rgba(255,255,255,0.16)"}));
    const draw=()=>{ctx.clearRect(0,0,c.width,c.height);pts.forEach(p=>{p.x+=p.vx;p.y+=p.vy;if(p.x<0||p.x>c.width)p.vx*=-1;if(p.y<0||p.y>c.height)p.vy*=-1;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=p.col;ctx.fill();});raf.current=requestAnimationFrame(draw);};
    draw();return()=>{cancelAnimationFrame(raf.current);window.removeEventListener("resize",resize);};
  },[]);
  return <canvas ref={canvas} style={{position:"absolute",inset:0,width:"100%",height:"100%",pointerEvents:"none",opacity:.5}}/>;
}
