function DeliveryCarousel(){
  const slides=[
    {img:IMG_ENTREGA1,caption:"Fiat Argo · Tucumán"},
    {img:IMG_ENTREGA2,caption:"Toyota Hilux · Yerba Buena"},
    {img:IMG_ENTREGA3,caption:"VW Amarok · Yerba Buena"},
    {img:IMG_ENTREGA4,caption:"VW Amarok V6 · Tucumán"},
    {img:IMG_ENTREGA5,caption:"VW Nivus · Yerba Buena"},
    {img:IMG_ENTREGA6,caption:"Peugeot 3008 · Yerba Buena"},
  ];
  const[cur,setCur]=useState(0);
  useEffect(()=>{const t=setInterval(()=>setCur(c=>(c+1)%slides.length),3800);return()=>clearInterval(t);},[]);
  return <section style={{padding:"100px 5vw",background:"linear-gradient(to bottom,#0e0e0e,#0a0a0a)"}}>
    <Reveal><Tag>Entregas reales</Tag></Reveal>
    <Reveal delay={.1}><SecH style={{marginBottom:14}}>Clientes <Red>felices</Red></SecH></Reveal>
    <Reveal delay={.15}><p style={{fontSize:13,color:C.muted,fontFamily:"sans-serif",marginBottom:48,maxWidth:480}}>Cada entrega es el inicio de una nueva historia. Acá las de nuestros clientes.</p></Reveal>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:2,background:C.border}}>
      <div style={{position:"relative",overflow:"hidden",aspectRatio:"3/4",gridRow:"span 2",background:"#0c0c0c"}}>
        <img src={slides[cur].img} alt={slides[cur].caption} style={{width:"100%",height:"100%",objectFit:"cover",objectPosition:"top"}}/>
        <div style={{position:"absolute",bottom:0,left:0,right:0,padding:"18px 20px",background:"linear-gradient(to top,rgba(0,0,0,.85),transparent)"}}>
          <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:14,fontWeight:700,color:"#fff",textTransform:"uppercase",letterSpacing:1}}>{slides[cur].caption}</div>
          <div style={{display:"flex",gap:7,marginTop:10}}>{slides.map((_,i)=><button key={i} onClick={()=>setCur(i)} style={{width:i===cur?24:8,height:4,background:i===cur?C.red:"rgba(255,255,255,.3)",border:"none",cursor:"pointer",transition:"all .3s",padding:0}}/>)}</div>
        </div>
      </div>
      {slides.slice(1,3).map((s,i)=><div key={i} style={{overflow:"hidden",aspectRatio:"3/2",background:"#0c0c0c",cursor:"pointer"}} onClick={()=>setCur(i+1)}>
        <img src={s.img} alt={s.caption} style={{width:"100%",height:"100%",objectFit:"cover",objectPosition:"top",filter:"brightness(.6)",transition:"all .4s"}}
          onMouseEnter={e=>{e.target.style.filter="brightness(.85)";e.target.style.transform="scale(1.04)"}}
          onMouseLeave={e=>{e.target.style.filter="brightness(.6)";e.target.style.transform="scale(1)"}}/>
      </div>)}
    </div>
  </section>;
}

function FAQ(){
  const[open,setOpen]=useState(null);
  const items=[
    {q:"¿Cómo funciona el proceso de compra?",a:"Es simple: elegís el auto, lo visitás en nuestra oficina de Galería Mercato, acordamos las condiciones y gestionamos toda la documentación. La transferencia es rápida y transparente."},
    {q:"¿Aceptan autos en permuta?",a:"Sí, tomamos tu auto como parte de pago al precio justo del mercado. Consultanos por WhatsApp con fotos y datos del vehículo para una tasación."},
    {q:"¿Ofrecen financiación?",a:"Sí, trabajamos con varias opciones de financiación. Podemos asesorarte sobre cuál se adapta mejor a tu situación. Consultanos sin compromiso."},
    {q:"¿Los autos tienen garantía?",a:"Todos los vehículos están revisados y documentados. Podemos gestionar garantía mecánica a través de nuestros socios. Cada caso lo analizamos en particular."},
    {q:"¿Hacen entregas a otras provincias?",a:"Sí, coordinamos entregas en todo el NOA y podemos gestionar envíos a otras provincias. Consultanos para ver tu situación específica."},
    {q:"¿Los precios son en pesos o dólares?",a:"Publicamos los precios en dólares como referencia, pero cerramos operaciones en pesos al tipo de cambio del día."},
    {q:"¿Cómo puedo ver un auto antes de comprarlo?",a:"Coordinás una visita por WhatsApp con Ale o Gonchi. Nos encontramos en Galería Mercato, Yerba Buena. Lunes a sábado de 9 a 20hs."},
  ];
  return <section style={{padding:"100px 5vw",background:C.carbon}}>
    <Reveal><Tag>Preguntas frecuentes</Tag></Reveal>
    <Reveal delay={.1}><SecH style={{marginBottom:48}}>Todo lo que <Red>necesitás saber</Red></SecH></Reveal>
    <div style={{maxWidth:760,display:"flex",flexDirection:"column",gap:1,background:C.border}}>
      {items.map((item,i)=><div key={i} style={{background:C.zinc,overflow:"hidden"}}>
        <button onClick={()=>setOpen(open===i?null:i)} style={{width:"100%",padding:"20px 22px",display:"flex",justifyContent:"space-between",alignItems:"center",background:"none",border:"none",cursor:"pointer",textAlign:"left",gap:16}}>
          <span style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:17,fontWeight:700,color:open===i?C.red:C.white,textTransform:"uppercase",letterSpacing:.5,transition:"color .25s"}}>{item.q}</span>
          <span style={{color:open===i?C.red:C.muted,fontSize:20,transition:"all .3s",transform:open===i?"rotate(45deg)":"rotate(0)",flexShrink:0}}>+</span>
        </button>
        <div style={{maxHeight:open===i?300:0,overflow:"hidden",transition:"max-height .4s ease"}}>
          <div style={{padding:"0 22px 20px",fontSize:13,color:"rgba(245,245,245,.52)",lineHeight:1.7,fontFamily:"sans-serif"}}>{item.a}</div>
        </div>
      </div>)}
    </div>
  </section>;
}

function Chatbot(){
  const[open,setOpen]=useState(false);
  const[msgs,setMsgs]=useState([{from:"bot",text:"¡Hola! Soy el asistente de NordenCars 🚗 ¿En qué puedo ayudarte?"}]);
  const[input,setInput]=useState("");const[typing,setTyping]=useState(false);const endRef=useRef();
  const SYSTEM=`Sos el asistente virtual de NordenCars, agencia de autos en Yerba Buena, Tucumán, Argentina. Fundadores: Ale y Gonchi. Tel Ale: +54 9 381 477-3142. Tel Gonchi: +54 9 381 518-4961. Ubicación: Galería Mercato, Casco Viejo, Yerba Buena. Horario: Lun-Sáb 9 a 20hs. Instagram: @norden.cars. Servicios: venta 0km y usados, permutas, financiación, gestión de documentación, entregas en el NOA. Respondé siempre en español, amigable y conciso.`;
  useEffect(()=>{endRef.current?.scrollIntoView({behavior:"smooth"});},[msgs,typing]);
  const send=async(text)=>{
    const t=(text||"").trim();if(!t)return;
    setInput("");setMsgs(m=>[...m,{from:"user",text:t}]);setTyping(true);
    try{
      const history=msgs.map(m=>({role:m.from==="user"?"user":"assistant",content:m.text}));
      const res=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json","anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},body:JSON.stringify({model:"claude-haiku-4-5-20251001",max_tokens:400,system:SYSTEM,messages:[...history,{role:"user",content:t}]})});
      const data=await res.json();
      setMsgs(m=>[...m,{from:"bot",text:data.content?.[0]?.text||"Disculpá, hubo un error. Escribinos por WhatsApp."}]);
    }catch{setMsgs(m=>[...m,{from:"bot",text:"Hubo un error. Podés escribirnos directo al WhatsApp 😊"}]);}
    setTyping(false);
  };
  return <>
    <button onClick={()=>setOpen(o=>!o)} style={{position:"fixed",bottom:96,right:28,zIndex:600,width:52,height:52,borderRadius:"50%",border:"none",background:"linear-gradient(135deg,#1c1c1c,#111)",cursor:"pointer",boxShadow:`0 4px 24px rgba(0,0,0,.6),0 0 0 1px ${C.border2}`,display:"flex",alignItems:"center",justifyContent:"center",transition:"all .3s",transform:open?"scale(1.08) rotate(45deg)":"scale(1)"}}>
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={open?C.red:"white"} strokeWidth="2" strokeLinecap="round">{open?<><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></>:<path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>}</svg>
      {!open&&<span style={{position:"absolute",top:-3,right:-3,width:14,height:14,borderRadius:"50%",background:"#22c55e",border:"2px solid #0a0a0a",fontSize:7,color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:700,fontFamily:"sans-serif"}}>IA</span>}
    </button>
    {open&&<div style={{position:"fixed",bottom:160,right:28,zIndex:601,width:320,background:"#111",border:`1px solid ${C.border2}`,display:"flex",flexDirection:"column",overflow:"hidden",boxShadow:"0 24px 80px rgba(0,0,0,.85)"}}>
      <div style={{background:`linear-gradient(135deg,#1a0505,${C.red})`,padding:"14px 16px",display:"flex",alignItems:"center",gap:10}}>
        <img src={IMG_LOGO} alt="NordenCars" style={{height:28,filter:"brightness(10)"}}/>
        <div><div style={{fontSize:12,fontWeight:600,color:"#fff",fontFamily:"sans-serif"}}>Asistente NordenCars</div><div style={{fontSize:9,color:"rgba(255,255,255,.75)",display:"flex",alignItems:"center",gap:4,fontFamily:"sans-serif"}}><span style={{width:5,height:5,background:"#4ade80",borderRadius:"50%",display:"inline-block"}}/>IA activa</div></div>
      </div>
      <div style={{padding:"8px 10px",borderBottom:`1px solid ${C.border}`,display:"flex",flexWrap:"wrap",gap:5}}>
        {["Ver stock","Financiación","Permutas","Ubicación","WhatsApp"].map(t=><button key={t} onClick={()=>send(t)} style={{fontSize:9,padding:"4px 10px",background:"rgba(220,38,38,.08)",border:`1px solid rgba(220,38,38,.18)`,color:C.red,cursor:"pointer",fontFamily:"sans-serif",borderRadius:20}}>{t}</button>)}
      </div>
      <div style={{flex:1,overflowY:"auto",padding:12,display:"flex",flexDirection:"column",gap:8,maxHeight:260,minHeight:180}}>
        {msgs.map((m,i)=><div key={i} style={{display:"flex",justifyContent:m.from==="user"?"flex-end":"flex-start"}}><div style={{maxWidth:"85%",padding:"9px 13px",fontSize:12,lineHeight:1.55,fontFamily:"sans-serif",background:m.from==="user"?C.red:"rgba(255,255,255,.06)",color:"#fff",borderRadius:m.from==="user"?"12px 12px 2px 12px":"12px 12px 12px 2px"}}>{m.text}</div></div>)}
        {typing&&<div style={{display:"flex"}}><div style={{padding:"9px 13px",background:"rgba(255,255,255,.06)",borderRadius:"12px 12px 12px 2px",display:"flex",gap:4,alignItems:"center"}}>{[0,1,2].map(i=><span key={i} style={{width:5,height:5,background:C.muted,borderRadius:"50%",animation:`dot .9s ${i*.2}s infinite`}}/>)}</div></div>}
        <div ref={endRef}/>
      </div>
      <div style={{padding:"9px 11px",borderTop:`1px solid ${C.border}`,display:"flex",gap:7}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&send(input)} placeholder="Escribí tu consulta..." style={{flex:1,background:"rgba(255,255,255,.04)",border:`1px solid ${C.border2}`,color:"#fff",padding:"9px 12px",fontSize:11,fontFamily:"sans-serif",outline:"none"}}/>
        <button onClick={()=>send(input)} style={{background:C.red,border:"none",color:"#fff",padding:"0 14px",cursor:"pointer",fontSize:15}}>→</button>
      </div>
    </div>}
    <style>{`@keyframes dot{0%,80%,100%{opacity:.2;transform:scale(.8)}40%{opacity:1;transform:scale(1)}}`}</style>
  </>;
}

