              <a href={`https://wa.me/${(c.telefono||"").replace(/\D/g,"")||"5493814773142"}?text=Hola%20${encodeURIComponent(c.nombre||"")}%2C%20te%20escribo%20de%20NordenCars!`} target="_blank" rel="noreferrer" style={{background:"#25D366",color:"#fff",padding:"6px 10px",fontSize:9,fontFamily:"sans-serif",textDecoration:"none",textAlign:"center"}}>WA</a>
